import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles/global.css';

const COLORS = {
  frontend: [63, 136, 197],
  backend:  [19, 111, 99],
  language: [255, 186, 8],
  ai:       [208, 0, 0],
  database: [3, 43, 67],
  tools:    [92, 107, 192],
  uiux:     [230, 81, 0],
};

const TECH = [
  { label: 'React',           r: 68, color: COLORS.frontend },
  { label: 'JavaScript',      r: 62, color: COLORS.frontend },
  { label: 'TypeScript',      r: 44, color: COLORS.frontend },
  { label: 'HTML / CSS',      r: 36, color: COLORS.uiux },
  { label: 'Python',          r: 64, color: COLORS.language },
  { label: 'C',               r: 30, color: COLORS.language },
  { label: 'FastAPI',         r: 54, color: COLORS.backend },
  { label: 'Atlassian Forge', r: 50, color: COLORS.tools },
  { label: 'REST APIs',       r: 40, color: COLORS.backend },
  { label: 'OpenAI API',      r: 58, color: COLORS.ai },
  { label: 'Supabase',        r: 52, color: COLORS.database },
  { label: 'PostgreSQL',      r: 46, color: COLORS.database },
  { label: 'Git',             r: 34, color: COLORS.tools },
];

const LEGEND = [
  { label: 'Frontend', color: COLORS.frontend },
  { label: 'Backend', color: COLORS.backend },
  { label: 'Language', color: COLORS.language },
  { label: 'AI', color: COLORS.ai },
  { label: 'Database', color: COLORS.database },
  { label: 'Tools', color: COLORS.tools },
  { label: 'UI/UX', color: COLORS.uiux },
];

const PROJECTS = [
  {
    name: 'StudySprinter',
    tag: 'AI · Full-Stack',
    desc: 'AI-powered study tool for generating flashcards and quizzes from any topic. Built full-stack from scratch with a ChatGPT-style sidebar, deck management, per-deck stats, and dark mode.',
    stack: ['React', 'FastAPI', 'Python', 'Supabase', 'OpenAI API', 'PostgreSQL'],
    github: 'https://github.com/annakuchina/studysprinter',
    live: 'https://studysprinter.vercel.app/',
    img: '/screenshots/studysprinter.png',
    reverse: false,
  },
  {
    name: 'Jira Pets',
    tag: 'Atlassian Forge · Capstone',
    desc: 'Gamified Jira dashboard plugin where your ticket activity drives a virtual pet system — XP, level progression, health, happiness, and an in-app shop. Built in a 6-person Agile team with mentorship from an Atlassian engineer.',
    stack: ['React', 'JavaScript', 'Atlassian Forge', 'Forge KVS', 'Agile'],
    github: null,
    live: null,
    img: '/screenshots/jirapets.png',
    reverse: true,
  },
];

const EARLIER = [
  { name: 'Tower Defence Game', tech: 'Python · Pygame · Procreate', img: '/screenshots/towerdefence.png', link: null },
  { name: 'Match-3 Game', tech: 'Python · Pygame · Procreate', img: '/screenshots/match3.png', link: null },
  { name: 'Drum Machine', tech: 'React · Redux · CSS', img: '/screenshots/drummachine.png', link: 'https://codepen.io/annakuchina' },
];

const STACK = [
  'React', 'JavaScript', 'TypeScript', 'Python',
  'FastAPI', 'Supabase', 'PostgreSQL', 'REST APIs',
  'Git', 'Atlassian Forge', 'HTML / CSS', 'OpenAI API',
];

function luminance(r, g, b) {
  const a = [r, g, b].map(v => {
    v /= 255;
    return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
  });
  return 0.2126 * a[0] + 0.7152 * a[1] + 0.0722 * a[2];
}

function getTextColor(r, g, b) {
  return luminance(r, g, b) > 0.4 ? '#111' : '#fff';
}

function fitFontSize(label, radius) {
  const maxWidth = radius * 1.6;
  const size = Math.floor(maxWidth / (label.length * 0.55));
  return Math.max(9, Math.min(size, radius * 0.55));
}

function initBubbles(W, H) {
  return TECH.map((t, i) => {
    const angle = (i / TECH.length) * Math.PI * 2;
    const dist = 70 + Math.random() * 50;
    return {
      x: W / 2 + Math.cos(angle) * dist,
      y: H / 2 + Math.sin(angle) * dist,
      vx: (Math.random() - 0.5) * 1.5,
      vy: (Math.random() - 0.5) * 1.5,
      r: t.r,
      label: t.label,
      color: t.color,
      textColor: getTextColor(...t.color),
      fontSize: fitFontSize(t.label, t.r),
    };
  });
}

function MetaballField() {
  const wrapperRef = useRef(null);
  const canvasRef = useRef(null);
  const bubblesRef = useRef([]);
  const dragRef = useRef(null);
  const rafRef = useRef(null);
  const sizeRef = useRef({ W: 500, H: 420 });
  const [, forceUpdate] = useState(0);

  useEffect(() => {
    if (!wrapperRef.current) return;
    const { width, height } = wrapperRef.current.getBoundingClientRect();
    const W = width || 500;
    const H = height || 420;
    sizeRef.current = { W, H };
    bubblesRef.current = initBubbles(W, H);

    const canvas = canvasRef.current;
    canvas.width = W;
    canvas.height = H;

    function draw() {
      const { W, H } = sizeRef.current;
      const ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, W, H);
      bubblesRef.current.forEach(b => {
        const [r, g, bl] = b.color;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgb(${r},${g},${bl})`;
        ctx.fill();
      });
    }

    function collide() {
      const bs = bubblesRef.current;
      for (let i = 0; i < bs.length; i++) {
        for (let j = i + 1; j < bs.length; j++) {
          const a = bs[i], b = bs[j];
          const dx = b.x - a.x, dy = b.y - a.y;
          const dist = Math.sqrt(dx * dx + dy * dy) || 0.001;
          const minD = a.r + b.r + 2;
          if (dist < minD) {
            const overlap = (minD - dist) / 2;
            const nx = dx / dist, ny = dy / dist;
            if (dragRef.current !== i) { a.x -= nx * overlap; a.y -= ny * overlap; }
            if (dragRef.current !== j) { b.x += nx * overlap; b.y += ny * overlap; }
            const dot = (a.vx - b.vx) * nx + (a.vy - b.vy) * ny;
            if (dot > 0) {
              a.vx -= (1 + 0.75) * dot * nx * 0.5;
              a.vy -= (1 + 0.75) * dot * ny * 0.5;
              b.vx += (1 + 0.75) * dot * nx * 0.5;
              b.vy += (1 + 0.75) * dot * ny * 0.5;
            }
          }
        }
      }
    }

    function tick() {
      const { W, H } = sizeRef.current;
      const cx = W / 2, cy = H / 2;
      bubblesRef.current = bubblesRef.current.map((b, i) => {
        if (dragRef.current === i) return b;
        const dx = cx - b.x, dy = cy - b.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 0.001;
        let vx = b.vx + (dx / dist) * 0.04;
        let vy = b.vy + (dy / dist) * 0.04;
        vx *= 0.985; vy *= 0.985;
        let x = b.x + vx, y = b.y + vy;
        if (x < b.r) { x = b.r; vx = Math.abs(vx) * 0.85; }
        if (x > W - b.r) { x = W - b.r; vx = -Math.abs(vx) * 0.85; }
        if (y < b.r) { y = b.r; vy = Math.abs(vy) * 0.85; }
        if (y > H - b.r) { y = H - b.r; vy = -Math.abs(vy) * 0.85; }
        return { ...b, x, y, vx, vy };
      });
      collide();
      draw();
      forceUpdate(n => n + 1);
      rafRef.current = requestAnimationFrame(tick);
    }

    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  const getPos = (e, rect) => ({
    x: (e.touches ? e.touches[0].clientX : e.clientX) - rect.left,
    y: (e.touches ? e.touches[0].clientY : e.clientY) - rect.top,
  });

  const onPointerDown = useCallback((e) => {
    const rect = wrapperRef.current.getBoundingClientRect();
    const { x, y } = getPos(e, rect);
    const hit = bubblesRef.current.findIndex(b => Math.hypot(b.x - x, b.y - y) < b.r);
    if (hit === -1) return;
    dragRef.current = hit;
    e.preventDefault();
    const onMove = (ev) => {
      ev.preventDefault();
      const { x, y } = getPos(ev, rect);
      bubblesRef.current = bubblesRef.current.map((b, i) =>
        i === hit ? { ...b, x, y, vx: 0, vy: 0 } : b
      );
    };
    const onUp = () => {
      dragRef.current = null;
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
  }, []);

  return (
    <div className="bubble-box">
      <div ref={wrapperRef} className="bubble-field" onPointerDown={onPointerDown} style={{ touchAction: 'none' }}>
        <canvas ref={canvasRef} style={{ display: 'block', width: '100%', height: '100%' }} />
        {TECH.map((t, i) => {
          const b = bubblesRef.current[i];
          if (!b) return null;
          return (
            <span
              key={t.label}
              style={{
                position: 'absolute',
                left: b.x,
                top: b.y,
                transform: 'translate(-50%, -50%)',
                fontSize: b.fontSize + 'px',
                fontWeight: 700,
                color: b.textColor,
                pointerEvents: 'none',
                whiteSpace: 'nowrap',
                letterSpacing: '0.02em',
              }}
            >
              {t.label}
            </span>
          );
        })}
      </div>
      <div className="bubble-legend">
        {LEGEND.map(l => (
          <div className="legend-item" key={l.label}>
            <span className="legend-dot" style={{ background: `rgb(${l.color[0]},${l.color[1]},${l.color[2]})` }} />
            {l.label}
          </div>
        ))}
      </div>
    </div>
  );
}

export default function App() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <>
      <nav style={{ boxShadow: scrolled ? '0 1px 0 rgba(0,0,0,0.06)' : 'none' }}>
        <a href="#home" className="nav-logo">Anna Kuchina</a>
        <ul className="nav-links">
          <li><a href="#projects">Projects</a></li>
          <li><a href="#about">About</a></li>
          <li><a href="#contact">Contact</a></li>
        </ul>
      </nav>

      <section className="hero" id="home">
        <div className="container">
          <div className="hero-inner">
            <div>
              <p className="hero-eyebrow">Full-Stack Developer · Sydney</p>
              <h1 className="hero-title">Building software that actually gets used.</h1>
              <p className="hero-bio">
                CS graduate from UNSW. I build full-stack and AI-assisted web apps —
                from the UI down to the API and database. Currently open to junior
                software engineering roles in Sydney or remote.
              </p>
              <div className="hero-links">
                <a href="#projects" className="btn btn-primary">View projects</a>
                <a href="https://github.com/annakuchina" target="_blank" rel="noreferrer" className="btn btn-outline">GitHub</a>
                <a href="https://linkedin.com/in/annakuchina" target="_blank" rel="noreferrer" className="btn btn-outline">LinkedIn</a>
              </div>
            </div>
            <MetaballField />
          </div>
        </div>
      </section>

      <section id="projects">
        <div className="container">
          <p className="section-eyebrow">Work</p>
          <h2 className="section-title">Projects</h2>
          {PROJECTS.map(p => (
            <div className="project-card" key={p.name}>
              <div className={`project-card-inner${p.reverse ? ' reverse' : ''}`}>
                <div className="project-screenshot">
                  <img src={p.img} alt={p.name} />
                </div>
                <div className="project-info">
                  <span className="project-tag">{p.tag}</span>
                  <h3 className="project-name">{p.name}</h3>
                  <p className="project-desc">{p.desc}</p>
                  <div className="project-stack">
                    {p.stack.map(s => <span className="stack-pill" key={s}>{s}</span>)}
                  </div>
                  <div className="project-links">
                    {p.github && <a href={p.github} target="_blank" rel="noreferrer" className="btn btn-outline" style={{ fontSize: '0.78rem', padding: '0.45rem 0.9rem' }}>GitHub</a>}
                    {p.live && <a href={p.live} target="_blank" rel="noreferrer" className="btn btn-primary" style={{ fontSize: '0.78rem', padding: '0.45rem 0.9rem' }}>Live demo</a>}
                    {!p.github && !p.live && <span style={{ fontSize: '0.73rem', color: '#999' }}>Available to discuss in interviews</span>}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section id="earlier">
        <div className="container">
          <p className="section-eyebrow">Before uni</p>
          <h2 className="section-title">Earlier work</h2>
          <div className="earlier-grid">
            {EARLIER.map(p => (
              <div className="earlier-card" key={p.name}>
                <img className="earlier-img" src={p.img} alt={p.name} />
                <div className="earlier-info">
                  <p className="earlier-name">{p.name}</p>
                  <p className="earlier-tech">{p.tech}</p>
                  {p.link && <a href={p.link} target="_blank" rel="noreferrer" className="btn btn-outline" style={{ fontSize: '0.73rem', padding: '0.35rem 0.8rem' }}>View</a>}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section id="about">
        <div className="container">
          <p className="section-eyebrow">Background</p>
          <h2 className="section-title">About</h2>
          <div className="about-grid">
            <div className="about-text">
              <p>Computer Science graduate from UNSW Sydney. I build full-stack web apps with a focus on clean UI, practical features, and code that actually works in production.</p>
              <p>My main project is StudySprinter — an AI-powered study tool I built from scratch using React, FastAPI, Supabase, and the OpenAI API. My capstone was Jira Pets, a gamified Jira plugin built on Atlassian Forge in a 6-person Agile team with mentorship from an Atlassian engineer.</p>
              <p>I use AI tools to move faster and write better software — not to skip the thinking. I completed a study abroad semester at Universitat de Barcelona in 2025.</p>
              <p>Outside of coding I train Muay Thai.</p>
            </div>
            <div>
              <p style={{ fontSize: '0.7rem', letterSpacing: '0.12em', textTransform: 'uppercase', color: '#999', marginBottom: '1rem', fontWeight: 500 }}>Tech stack</p>
              <div className="stack-grid">
                {STACK.map(s => (
                  <div className="stack-item" key={s}>
                    <span className="stack-dot"></span>
                    {s}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </section>

      <section id="contact">
        <div className="container">
          <div className="contact-inner">
            <h2 className="contact-title">Open to work</h2>
            <p className="contact-sub">
              Looking for junior software engineering roles in Sydney or remote/hybrid Australia.
              Frontend, full-stack, or anything where I'll write real code.
            </p>
